// Grab the AI's response (adjust 'output' to 'text' if your node uses that)
let aiResponse = $input.first().json.output || $input.first().json.text || $input.first().json.message.content;

// Clean up any weird AI markdown formatting
aiResponse = aiResponse.replace(/```json/g, '').replace(/```/g, '').trim();

// Convert the text into an actual data array
let ideas = JSON.parse(aiResponse);

// Split them into separate n8n items
return ideas.map(idea => ({ json: idea }));
